WebLink.url:
{!REQUIRESCRIPT('/soap/ajax/47.0/connection.js')}
{!REQUIRESCRIPT('/soap/ajax/47.0/apex.js')}

//ステータス＝「研修省略」また「未評価」
if('{!Human__c.Status__c}' == '未評価' && '{!Human__c.KensyuKibou__c}' == '受講する') {
  //登録前面談の評価≠Nullの場合
  if('{!Human__c.Interview_Review__c}' != ''){
    var result = sforce.apex.execute('SFTR_O_HumanWebService', 'idIssue', {itemId :  '{!Human__c.Id}'});
    if (result == '成功') {
      alert('ID発行済みでした');
      location.reload();
    } else {
      alert('ID発行が失敗しました');
    }
  } else {
    alert('登録前面談の評価を入力し、ID発行を処理してください。');
  }
} else {
 alert('この処理は実行できません。');
}
